const objeciones = Number(pick(payload.objeciones, dcv("score_objeciones"))) || 8.2;
const cierre = Number(pick(payload.cierre, dcv("score_cierre"))) || 7.0;
const escucha = Number(pick(payload.escucha, dcv("score_lectura_sala"))) || 9.0;

// FIX: "modulo" (el campo real que llena el agente con el modulo/escenario practicado)
// nunca se leia; el email siempre mostraba el fallback generico "Sesion de coaching".
const moduloReal = pick(payload.modulos_practicados, payload.escenario, payload.tipo_actividad, dcv("modulo"));

// FIX: el campo real es "recomendaciones" (plural); el codigo buscaba
// "recomendacion_siguiente" (singular, esquema viejo) y nunca hacia match ->
// el correo siempre mostraba el consejo generico en vez del real del coach.
const recomendacionReal = pick(payload.recomendacion_siguiente, dcv("recomendaciones"), dcv("recomendacion_siguiente"));

// FIX: fecha/hora reales de la sesion (fecha_sesion/hora_inicio/hora_fin) — antes
// el email siempre mostraba la fecha del momento en que corre el workflow y una
// hora fija de ejemplo (14:35–15:03), sin importar cuando fue la sesion real.
const fechaReal = pick(payload.fecha_formato, dcv("fecha_sesion"));
const horaInicioReal = pick(payload.hora_inicio, dcv("hora_inicio"));
const horaFinReal = pick(payload.hora_fin, dcv("hora_fin"));

return {
    success: true,
    conversation_id: payload.conversation_id || "AUTO_" + Date.now(),

    // Identidad
    employee_name: nombre,
    nombre: nombre,
    empleado_id: empleadoId,
    puesto: puesto,
    departamento: departamento,
    idioma: idioma,

    // Métricas (0-10)
    score: payload.scoreTotal || payload.score || 0,
    scoreTotal: scoreTotal,
    rapport: rapport,
    pnl: pnl,
    postura: postura,
    objeciones: objeciones,
    cierre: cierre,
    escucha: escucha,
    potencial_mejora: potencialMejora,

    // Narrativa
    resumen: pick(payload.resumen, analysis.transcript_summary, dcv("recomendacion_siguiente")) || "Sesión completada.",
    fortalezas: pick(payload.fortalezas, dcv("fortalezas")) || "Buena disposición y actitud durante la práctica.",
    areas_mejora: pick(payload.areas_mejora, dcv("areas_mejora")) || "Reforzar los fundamentos del módulo practicado.",
    analisis_pnl: payload.analisis_pnl || "Sin patrones PNL destacados en esta sesión.",
    recomendacion_siguiente: recomendacionReal || "Repasar el módulo con menor puntaje.",

    // Escenario / módulos
    escenario: pick(payload.escenario, dcv("escenario_roleplay"), moduloReal) || "Sesión de coaching",
    tipo_actividad: pick(payload.tipo_actividad, dcv("tipo_actividad")) || "Roleplay",
    modulos_practicados: moduloReal || "",

    // Fecha / hora / duración
    fecha_formato: fechaReal || `${dia}-${mes}-${anio}`,
    hora_inicio: horaInicioReal || "14:35",
    hora_fin: horaFinReal || "15:03",
    duracion_minutos: duracionMinutos,
    duracion_texto: duracionTexto,
    sesion_numero: payload.sesion_numero || 1,

    // Datos crudos del data_collection (25 campos) — se pasan tal cual por si algun
    // consumidor futuro (PDF, dashboard, Sheets) los necesita sin re-parsear el payload.
    quiz_realizado: pick(dcv("quiz_realizado"), payload.quiz_realizado) || "",
    quiz_score: pick(dcv("quiz_score"), payload.quiz_score) || "",
    disc_prospecto: pick(dcv("disc_prospecto"), payload.disc_prospecto) || "",
    score_disc_flex: Number(pick(payload.score_disc_flex, dcv("score_disc_flex"))) || null,

    // Plan de acción (gerente)
    accion1: payload.accion1 || "Reducir Interrupciones",
    accion1_desc: payload.accion1_desc || "Pausas prolongadas entre argumentos.",
    accion2: payload.accion2 || "Memorizar el Pitch",
    accion2_desc: payload.accion2_desc || "Dudar en el pitch resta credibilidad.",
    accion3: payload.accion3 || "Dominar el Cierre",
    accion3_desc: payload.accion3_desc || "Falta de confianza al cerrar.",

    // Frecuencia de temas (escala 0-10)
    precio: payload.precio != null ? payload.precio : 8,
    incentivos: payload.incentivos != null ? payload.incentivos : 6,
    tiempo: payload.tiempo != null ? payload.tiempo : 10,
    indecision: payload.indecision != null ? payload.indecision : 4,

    // Distribución de tiempo por actividad (%, deben sumar ~100)
    pct_pitch: payload.pct_pitch != null ? payload.pct_pitch : 50,
    pct_warmup: payload.pct_warmup != null ? payload.pct_warmup : 20,
    pct_objeciones: payload.pct_objeciones != null ? payload.pct_objeciones : 15,
    pct_cierre: payload.pct_cierre != null ? payload.pct_cierre : 15,

    // Principios neurocientíficos (%)
    pct_patrones: payload.pct_patrones != null ? payload.pct_patrones : 50,
    pct_fraseologia: payload.pct_fraseologia != null ? payload.pct_fraseologia : 50,
    pct_contexto: payload.pct_contexto != null ? payload.pct_contexto : 50,

    // Datos ricos OPCIONALES — solo se muestran en el reporte si vienen reales
    // (nunca se inventa contenido de ejemplo para una sesión real).
    transcript: Array.isArray(payload.transcript) ? payload.transcript : null,
    historial: Array.isArray(payload.historial) ? payload.historial : null,
    quiz: Array.isArray(payload.quiz) ? payload.quiz : null,
    objeciones_detalle: Array.isArray(payload.objeciones_detalle) ? payload.objeciones_detalle : null,
};

// Generar Email — VTC Elite Reporting
// CAMBIO: cuerpo del correo = SOLO texto profesional (no HTML visual).
// El reporte visual va como PDF adjunto; audio (MP3) y transcripcion (TXT)
// tambien adjuntos. Recibe UN item de "Preparar Datos".
const d = $input.first().json;

function v(x, def){ return (x == null || x === "") ? (def || "") : String(x); }

const nombre         = v(d.nombre || d.employee_name, "Asesor");
const fecha          = v(d.fecha_formato, "-");
const hora           = v(d.hora_inicio, "-");
const duracion       = d.duracion_texto ? v(d.duracion_texto) : (v(d.duracion_minutos, "-") + " minutos");
const modulo         = v(d.modulos_practicados || d.escenario, "-");
const score          = v(d.scoreTotal, "-");
const idioma         = v(d.idioma, "-");
const resumen        = v(d.resumen, "-");
const fortalezas     = v(d.fortalezas, "-");
const areas          = v(d.areas_mejora, "-");
const recomendaciones= v(d.recomendacion_siguiente, "-");

const linea = "------------------------------------------------------------";

const text =
"Estimado " + nombre + ",\n\n" +
"Le enviamos el resumen de su sesion de entrenamiento del " + fecha + " a las " + hora + ".\n\n" +
"RESUMEN DE LA SESION\n" +
"Duracion: " + duracion + "\n" +
"Modulo: " + modulo + "\n" +
"Desempeno general: " + score + "/10\n" +
"Idioma: " + idioma + "\n\n" +
"ANALISIS:\n" + resumen + "\n\n" +
"FORTALEZAS IDENTIFICADAS:\n" + fortalezas + "\n\n" +
"AREAS A MEJORAR:\n" + areas + "\n\n" +
"RECOMENDACION DEL COACH:\n" + recomendaciones + "\n\n" +
linea + "\n\n" +
"PROXIMOS PASOS\n\n" +
"Para acceder al reporte completo con graficos, analisis detallado de competencias y plan de accion personalizado, descargue el archivo PDF adjunto.\n\n" +
"Para revisar la transcripcion completa de la sesion, descargue el archivo de audio (MP3) y la transcripcion de texto (TXT) adjuntos.\n\n" +
linea + "\n\n" +
"Quedo atento a cualquier pregunta.\n\n" +
"Saludos cordiales,\n\n" +
"El equipo de Victor-IA\n" +
"Entrenamiento VTC Capacitacion\n" +
"victor-ia.com.mx\n";

// Se conserva la llave "html" apuntando al mismo texto por compatibilidad,
// pero el nodo "Send an Email" usa emailFormat=text -> se envia como texto plano.
return { text: text, html: text };
